+function drawTiledWall(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
+  const wc: Record<CharacterType, [string, string, string]> = {
+    king: ['#3e3650', '#484060', '#353048'], nobility: ['#3a3850', '#44405a', '#323048'],
+    knight: ['#384050', '#404858', '#303848'], squire: ['#384038', '#404840', '#303830'],
+    healer: ['#303850', '#384058', '#282e48'], sentinel: ['#303848', '#3a4050', '#282e40'],
+    scribe: ['#3a3430', '#443c38', '#322c28'], judge: ['#383040', '#403848', '#302838'],
+    blacksmith: ['#383028', '#403830', '#302820'],
+  };
+  const [base, light, dark] = wc[type];
+
+  // Fill base wall color
+  ctx.fillStyle = base;
+  ctx.fillRect(x, y, w, h);
+
+  const bW = 20, bH = 10, seed = x * 7 + y * 13;
+
+  // Helper to lighten/darken hex colors by a percentage
+  function shadeColor(color: string, percent: number) {
+    const num = parseInt(color.slice(1), 16);
+    let r = (num >> 16) & 0xFF;
+    let g = (num >> 8) & 0xFF;
+    let b = num & 0xFF;
+    r = Math.min(255, Math.max(0, r + (r * percent) | 0));
+    g = Math.min(255, Math.max(0, g + (g * percent) | 0));
+    b = Math.min(255, Math.max(0, b + (b * percent) | 0));
+    return `rgb(${r},${g},${b})`;
+  }
+
+  // Draw bricks with color variation and mortar lines
+  for (let row = 0; row < Math.ceil(h / bH); row++) {
+    const off = row % 2 === 0 ? 0 : bW * 0.5;
+    for (let col = -1; col < Math.ceil(w / bW) + 1; col++) {
+      const bx = x + col * bW + off, by = y + row * bH;
+      if (bx + bW < x || bx > x + w) continue;
+
+      // Random shade variation ±10%
+      const hash = ((bx * 31 + by * 17 + seed) & 0xFF) / 255;
+      const shadeOffset = (hash - 0.5) * 0.2; // ±0.1
+      const brickColor = shadeColor(base, shadeOffset);
+
+      // Draw brick body inset by 1px for mortar lines
+      ctx.fillStyle = brickColor;
+      ctx.fillRect(bx + 1, by + 1, bW - 2, bH - 2);
+    }
+  }
+
+  // Draw mortar lines (1px lighter lines in brick pattern)
+  ctx.strokeStyle = shadeColor(base, 0.3);
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  // Horizontal mortar lines
+  for (let row = 0; row <= Math.ceil(h / bH); row++) {
+    const yLine = y + row * bH + 0.5;
+    ctx.moveTo(x, yLine);
+    ctx.lineTo(x + w, yLine);
+  }
+  // Vertical mortar lines with offset every other row
+  for (let row = 0; row < Math.ceil(h / bH); row++) {
+    const off = row % 2 === 0 ? 0 : bW * 0.5;
+    const yStart = y + row * bH + 0.5;
+    const yEnd = yStart + bH;
+    for (let col = 0; col <= Math.ceil(w / bW) + 1; col++) {
+      const xLine = x + col * bW + off + 0.5;
+      if (xLine < x || xLine > x + w) continue;
+      ctx.moveTo(xLine, yStart);
+      ctx.lineTo(xLine, yEnd);
+    }
+  }
+  ctx.stroke();
+
+  // Draw shadow gradient (darker at bottom, lighter at top)
+  const grad = ctx.createLinearGradient(x, y, x, y + h);
+  grad.addColorStop(0, shadeColor(base, 0.15));
+  grad.addColorStop(1, shadeColor(base, -0.25));
+  ctx.fillStyle = grad;
+  ctx.fillRect(x, y, w, h);
+
+  // Draw subtle highlight line at top edge
+  ctx.fillStyle = 'rgba(255,255,255,0.1)';
+  ctx.fillRect(x, y, w, 2);
+}
